//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "FI054", compID : "lc_eisAcctDeptCd", opt :{"range" : "1"}},
        { grpCd : "CO012", compID : "lc_unit"}        
    ];
    $c.data.setCommonCode(codeOptions);

    gr_master.setHeaderHide(true);
	scwin.f_FieldClear();	
};

//-------------------------------------------------------------------------
// onUdcCompleted
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    // ed_srchCloseYY.setValue(scwin.fromDate_Yy);
    //$c.gus.cfDisableKey();
}

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function() {      
    scwin.f_SetDefaultUnit();
}

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit= function () {
    var rcnt =  dlt_commonCodeCO012.getRowCount();
    if (rcnt < 1) return;
    var index = 0;
    for (i=0; i < rcnt; i++) {  
        if (dlt_commonCodeCO012.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
           index = i;
           break;
       }
    }
    //lc_unit.setSelectedIndex(index);  
    lc_unit.setSelectedIndex(2);  
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {
    scwin.f_CloseYm();
    chk_distYn.checkAll(false);   
    ed_srchCloseYY.focus();
    lc_eisAcctDeptCd.setSelectedIndex(0);
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
 //   $c.gus.cfInitObjects(tbl_search,[ed_srchCloseYY]);
    scwin.f_SetSrchDefault();
}
//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
//    버전이 001일경우는 장부구분의 (자산비용)을 조회 하도록 코드값을 변경한다.
//    ds_search.NameString(ds_search.RowPosition,"bookClsCd") = "801";		
//    ds_search.NameString(ds_search.RowPosition,"ver") = "002";

    gr_master.initGrid();

    // scwin.pfromMM = WebSquare.date.getCurrentServerDate("MM");
    // scwin.pcloseYm = ed_srchCloseYY.getValue()+scwin.pfromMM;

    //scwin.pcloseYm = scwin.fromDate_Yy;
    scwin.pcloseYm = ed_srchCloseYY.getValue();

    dma_search.set("bookClsCd", "801");
    dma_search.set("ver", "002");

    dma_search.set("closeYm", scwin.pcloseYm); 
    dma_search.set("acctDeptCd", lc_eisAcctDeptCd.getValue());
    dma_search.set("eisAcctDeptCd","1");
   // eisAcctDeptCd : 0 일때 월별추이실적조회 , 1:법인별손익추이, 2:사업영역별손익추이
   // dma_search.set("coCd", scwin.vLoginCoCd);    
   // dma_search.set("DpctYn", 0);
   // dma_search.set("ExceptionDeptYn", 0); 
   // dma_search.set("bizDomCd", "0");

    dma_search.set("distYn", scwin.tDist);

    $c.sbm.execute(sbm_master);

}

//-------------------------------------------------------------------------
// 마지막 마감년월를 구한다.
//-------------------------------------------------------------------------	
scwin.f_CloseYm = function() { 
    dma_closeYm.set("sysCd", "ManagementProfitAndLossEBC");
    dma_closeYm.set("queryId", "retrieveManagementProfitAndLossCloseYm");

    $c.sbm.execute(sbm_closeYm);
}

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
   if(ds_master.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_master.getTotalCol(); i++){
        if(gr_master.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_srchCloseYY.getValue().trim(), "####-##");
    let str1 = $c.gus.cfGetFormatStr(ed_srchCloseYY.getValue().trim(), "######");
    let str2 = lc_eisAcctDeptCd.getValue(); 
    let str21 = lc_eisAcctDeptCd.getText(); 

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "손익추이_"+str1,
        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "결산년도 ["+ str +"]",
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 3,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "구분 ["+ str21 +"]" ,
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 

    }]

    const options = {
        fileName: "손익추이_"+str1+".xlsx",
        sheetName:"손익추이_"+str1,
        startRowIndex: 0,
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_master, options);
};

